class QueryGenerator:
    def expand(self, query):
        keywords = query.split()
        synonyms = {kw: self.synonym_map.get(kw, kw) for kw in keywords}
        return list(set(keywords + synonyms.values()))

function aggregateRetrievalResults(results) {
  const total = results.reduce((sum, r) => sum + r.count, 0);
  const avgScore = results.reduce((sum, r) => sum + r.score, 0) / results.length;
  return { total, avgScore, count: results.length };
}

